// Generated by OrchestKit Claude Plugin

// Guards the orank "OpenAPI spec published" + "NLWeb streaming" recovery:
// the spec must be reachable at the exact paths agent-readiness scanners probe
// (/openapi.json via rewrite → /api/openapi, plus the /api/openapi.yaml twin),
// and /ask must honor the RFC 7240 `Prefer: streaming` header. Pure handler
// invocations — no server, no network.

import { describe, expect, it } from "vitest";
import { GET as getOpenApiJson } from "@/app/api/openapi/route";
import { GET as getOpenApiYaml } from "@/app/api/openapi-yaml/route";
import { buildOpenApiSpec } from "@/lib/openapi/spec";
import { isServedPath } from "@/lib/agent-404";

describe("OpenAPI spec content", () => {
	it("is a valid OpenAPI 3.1 document with paths + components", () => {
		const spec = buildOpenApiSpec();
		expect(spec.openapi).toBe("3.1.0");
		expect(spec.info.title).toContain("OrchestKit");
		expect(Object.keys(spec.paths).length).toBeGreaterThan(0);
		expect(spec.components).toBeTruthy();
	});
});

describe("/api/openapi (JSON surface)", () => {
	it("returns 200 JSON that parses to a 3.1 spec", async () => {
		const res = getOpenApiJson();
		expect(res.status).toBe(200);
		expect(res.headers.get("Content-Type")).toBe("application/json; charset=utf-8");
		const parsed = JSON.parse(await res.text());
		expect(parsed.openapi).toBe("3.1.0");
		expect(Object.keys(parsed.paths).length).toBeGreaterThan(0);
	});
});

describe("/api/openapi.yaml (YAML twin)", () => {
	it("returns 200 with a YAML content-type and a parseable spec", async () => {
		const res = getOpenApiYaml();
		expect(res.status).toBe(200);
		expect(res.headers.get("Content-Type")).toBe("application/yaml; charset=utf-8");
		// YAML 1.2 is a JSON superset, so the body parses as JSON too — assert the
		// served body is the same spec object as the JSON surface.
		const parsed = JSON.parse(await res.text());
		expect(parsed.openapi).toBe("3.1.0");
		expect(parsed.info.title).toBe(buildOpenApiSpec().info.title);
	});
});

describe("orank probe paths are registered as served", () => {
	it("/openapi.json and /api/openapi.yaml resolve to served paths", () => {
		// /openapi.json is a top-level .json rewrite → must be in SERVED_EXACT so
		// agents get the spec, not a synthesized JSON 404.
		expect(isServedPath("/openapi.json")).toBe(true);
		// /api/openapi.yaml is covered by the /api served prefix.
		expect(isServedPath("/api/openapi.yaml")).toBe(true);
	});
});
